import{c as n}from"./Cdp7ABTo.js";const c={async listClinics(){return(await n.get("/clinics")).data},async getClinic(t){return(await n.get(`/clinics/${t}`)).data},async getClinicPatients(t){return(await n.get(`/clinics/${t}/patients`)).data},async updateAppointmentStatus(t,s,e){return(await n.put(`/clinics/${t}/appointments/${s}/status`,{status:e})).data},async getFacultyClinics(t){return(await n.get(`/clinics/faculty/${t}/clinics`)).data},async getPatientAppointments(t){return(await n.get(`/clinics/patient/${t}/appointments`)).data},async searchPatient(t,s){return(await n.get(`/clinics/${t}/search-patient`,{params:{q:s}})).data},async checkInPatient(t,s){return(await n.post(`/clinics/${t}/check-in`,s)).data},async createAppointment(t,s){return(await n.post(`/clinics/${t}/appointments`,s)).data},async createClinic(t){return(await n.post("/clinics",t)).data},async updateClinic(t,s){return(await n.put(`/clinics/${t}`,s)).data},async deleteClinic(t){await n.delete(`/clinics/${t}`)},async listClinicsPublic(){return(await n.get("/clinics/public")).data}};export{c};
